#include<bits/stdc++.h>
using namespace std;
struct ve{
	int a[1005],s;
};
map<string,ve>mp;
int l,n,m;string str;
int main(void){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>l;
		while(l--){
			cin>>str;
			if(mp[str].a[mp[str].s]!=i)mp[str].s+=1,mp[str].a[mp[str].s]=i; 
		}
	}
	cin>>m;
	while(m--){
		cin>>str;
		for(int i=1;i<=mp[str].s;i++){
			cout<<mp[str].a[i]<<' ';
		}cout<<"\n";
	}
    return false;
}
